                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between items-center pt-4 border-t border-gray-100 mt-2">
            {isDeleteConfirmOpen ? (
                <div className="flex items-center justify-between w-full animate-in fade-in slide-in-from-left-2 bg-red-50 p-2 rounded-lg border border-red-100">
                    <span className="text-sm font-semibold text-red-700 flex items-center gap-2">
                        <AlertCircle size={16} />
                        Confirm deletion?
                    </span>
                    <div className="flex gap-2">
                        <button 
                            type="button"
                            onClick={() => setIsDeleteConfirmOpen(false)}
                            className="px-3 py-1.5 text-xs font-medium text-gray-600 bg-white border border-gray-200 hover:bg-gray-50 rounded-md transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            type="button"
                            onClick={() => onDelete && existingEvent && onDelete(existingEvent)}
                            className="px-3 py-1.5 text-xs font-medium text-white bg-red-600 hover:bg-red-700 rounded-md transition-colors shadow-sm"
                        >
                            Delete
                        </button>
                    </div>
                </div>
            ) : (
                <>
                    {/* Left Side: Delete Button */}
                    <div>
                        {isAdmin && existingEvent && onDelete && (
                            <button 
                                type="button" 
                                onClick={() => setIsDeleteConfirmOpen(true)}
                                className="flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            >
                                <Trash2 size={16} />
                                Delete
                            </button>
                        )}
                    </div>

                    {/* Right Side: Action Buttons */}
                    <div className="flex gap-2">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                        <button 
                            type="submit" 
                            className={`px-4 py-2 text-sm font-medium text-white rounded-lg transition-colors shadow-sm ${timeError ? 'bg-blue-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
                        >
                            {isAdmin 
                                ? (existingEvent ? 'Update Event' : 'Create Event') 
                                : (existingEvent ? 'Request Edit' : 'Propose')
                            }
                        </button>
                    </div>
                </>
            )}
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, Plus, Calendar as CalendarLogo, Repeat, ShieldCheck, LayoutDashboard, Filter, ChevronDown, LogOut } from 'lucide-react';
import { CalendarEvent, Region, DayData } from './types';
import { 
    generateCalendarGrid, 
    MONTH_NAMES, 
    WEEK_DAYS, 
    isSameDay, 
    isEventActiveOnDate,
    formatTime,
    getRegionClasses 
} from './utils/dateUtils';
import { EventModal } from './components/EventModal';
import { MonthYearSelector } from './components/MonthYearSelector';
import { AdminDashboard } from './components/AdminDashboard';
import { LoginModal } from './components/LoginModal';
import { getEvents, addEvent, updateEvent, softDeleteEvent } from './lib/firebase';

export const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [selectedRegionFilter, setSelectedRegionFilter] = useState<Region | 'All'>('All');

  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [isMonthPickerOpen, setIsMonthPickerOpen] = useState(false);
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);

  const [view, setView] = useState<'calendar' | 'admin'>('calendar');
  const [isAdminSession, setIsAdminSession] = useState(false);

  const monthPickerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Subscribe to Firebase updates from the 'events' collection only
    const unsubscribe = getEvents((fetchedEvents) => {
        setEvents(fetchedEvents);
    });

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (monthPickerRef.current && !monthPickerRef.current.contains(event.target as Node)) {
        setIsMonthPickerOpen(false);
      }
    };
    if (isMonthPickerOpen) document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isMonthPickerOpen]);

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const handleJumpToToday = () => {
    setCurrentDate(new Date());
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setSelectedEvent(null);
    setIsEventModalOpen(true);
  };

  const handleEventClick = (e: React.MouseEvent, event: CalendarEvent) => {
    e.stopPropagation();
    setSelectedEvent(event);
    setSelectedDate(new Date(event.start));
    setIsEventModalOpen(true);
  };

  const handleSaveEvent = async (event: CalendarEvent) => {
    // Check if we are updating an existing event
    const isUpdate = !!selectedEvent || events.some(e => e.id === event.id);

    // Prepare the event data based on session type
    const finalEvent = { ...event };

    if (isAdminSession) {
        // Admins: Direct approval and update
        finalEvent.status = 'approved';
        // Cleanup snapshot data as it's not needed for direct updates
        if (finalEvent.originalData) {
            delete finalEvent.originalData;
        }
    } 
    // Non-Admins: status is already set to 'pending' or 'edited' by EventModal

    if (isUpdate) {
        // This will route to 'pending_events' if status is 'edited', or update 'events' if 'approved'
        await updateEvent(finalEvent);
    } else {
        // This will route to 'pending_events' if status is 'pending', or add to 'events' if 'approved'
        const { id, ...eventData } = finalEvent;
        await addEvent(eventData);
    }
  };

  const handleDeleteEvent = async (event: CalendarEvent) => {
    try {
        await softDeleteEvent(event);
        setIsEventModalOpen(false);
        setSelectedEvent(null);
    } catch (error) {
        console.error("Failed to delete event", error);
        alert("Failed to delete event. Please try again.");
    }
  };

  const handleAdminAccess = () => {
      if (isAdminSession) {
          setView('admin');
      } else {
          setIsLoginModalOpen(true);
      }
  };

  const handleLoginSuccess = () => {
      setIsAdminSession(true);
      setIsLoginModalOpen(false);
      setView('admin');
  };

  const handleLogout = () => {
      setIsAdminSession(false);
      setView('calendar');
  };

  const gridData = generateCalendarGrid(currentDate);

  // Filter events for the calendar view (only show approved events and match region filter)
  // Note: 'events' state comes strictly from the 'events' collection
  const approvedEvents = events.filter(e => {
      const isApproved = e.status === 'approved';
      const matchesRegion = selectedRegionFilter === 'All' || e.region === selectedRegionFilter;
      return isApproved && matchesRegion;
  });

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900 font-sans">
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('calendar')}>
            <div className="bg-blue-600 p-2 rounded-xl text-white shadow-lg shadow-blue-200">
                <CalendarLogo size={24} />
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-gray-800">AJET Event Calendar</h1>
        </div>

        {view === 'calendar' && (
            <div className="flex items-center gap-4 bg-gray-100/50 p-1.5 rounded-2xl border border-gray-200/50">
                <button onClick={handlePrevMonth} className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md">
                    <ChevronLeft size={20} />
                </button>
                <div className="relative" ref={monthPickerRef}>
                    <button onClick={() => setIsMonthPickerOpen(!isMonthPickerOpen)} className="px-3 py-1 hover:bg-white rounded-xl text-gray-800 transition-all shadow-sm hover:shadow-md border border-transparent hover:border-gray-200 min-w-[140px]">
                        <span className="text-lg font-semibold select-none block text-center">
                            {MONTH_NAMES[currentDate.getMonth()]} {currentDate.getFullYear()}
                        </span>
                    </button>
                    {isMonthPickerOpen && (
                        <MonthYearSelector 
                            currentDate={currentDate} 
                            onChange={(date) => { setCurrentDate(date); setIsMonthPickerOpen(false); }}
                            onClose={() => setIsMonthPickerOpen(false)}
                        />
                    )}
                </div>
                <button onClick={handleNextMonth} className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md">
                    <ChevronRight size={20} />
                </button>
            </div>
        )}

        <div className="flex items-center gap-3 w-full md:w-auto">
            {view === 'calendar' ? (
                <>
                    {/* Region Filter */}
                    <div className="relative">
                        <div className="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none text-gray-400">
                            <Filter size={14} />
                        </div>
                        <select
                            value={selectedRegionFilter}
                            onChange={(e) => setSelectedRegionFilter(e.target.value as Region | 'All')}
                            className="pl-8 pr-8 py-2 text-sm font-medium text-gray-600 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer shadow-sm transition-all h-[38px] min-w-[150px]"
                        >
                            <option value="All">All Regions</option>
                            {Object.values(Region).map((r) => (
                                <option key={r} value={r}>{r}</option>
                            ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 pr-2.5 flex items-center pointer-events-none text-gray-400">
                            <ChevronDown size={14} />
                        </div>
                    </div>

                    <div className="w-px h-6 bg-gray-300 mx-1"></div>

                    <button 
                        onClick={handleAdminAccess} 
                        className={`p-2 rounded-lg transition-colors ${isAdminSession ? 'text-blue-600 bg-blue-50' : 'text-gray-500 hover:text-gray-800 hover:bg-gray-100'}`}
                        title={isAdminSession ? "Go to Dashboard" : "Admin Login"}
                    >
                        <ShieldCheck size={20} />
                    </button>
                    <button onClick={handleJumpToToday} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors border border-gray-200 bg-white">Today</button>
                    <button onClick={() => { setSelectedDate(null); setSelectedEvent(null); setIsEventModalOpen(true); }} className="flex items-center justify-center p-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-all shadow-md shadow-blue-100 hover:shadow-lg">
                        <Plus size={20} />
                    </button>
                </>
            ) : (
                <div className="flex items-center gap-2">
                    <button 
                        onClick={handleLogout}
                        className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    >
                        <LogOut size={18} />
                        <span className="hidden sm:inline">Log Out</span>
                    </button>
                    <button 
                        onClick={() => setView('calendar')} 
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-100 rounded-lg transition-colors border border-gray-200 bg-white"
                    >
                        <LayoutDashboard size={18} />
                        Back to Calendar
                    </button>
                </div>
            )}
        </div>
      </header>

      <main className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col">
        {view === 'admin' && isAdminSession ? (
            <AdminDashboard />
        ) : view === 'admin' ? (
             <div className="flex items-center justify-center h-full">
                 <p className="text-gray-500">Please log in to view the dashboard.</p>
             </div>
        ) : (
            <>
                {isAdminSession && (
                    <div className="bg-gray-900 text-white rounded-xl p-4 mb-4 flex flex-col sm:flex-row items-center justify-between gap-4 shadow-lg animate-in fade-in slide-in-from-top-2">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-gray-800 rounded-lg border border-gray-700">
                                <ShieldCheck size={20} className="text-emerald-400" />
                            </div>
                            <div>
                                <h3 className="text-sm font-bold text-white">Admin Session Active</h3>
                                <p className="text-xs text-gray-400">You have full administrative access to the calendar.</p>
                            </div>
                        </div>
                        <button 
                            onClick={handleLogout}
                            className="w-full sm:w-auto flex items-center justify-center gap-2 px-4 py-2 text-xs font-semibold text-red-300 bg-red-950/30 hover:bg-red-950/50 border border-red-900/50 rounded-lg transition-colors"
                        >
                            <LogOut size={14} />
                            Log Out
                        </button>
                    </div>
                )}

                <div className="grid grid-cols-7 mb-4">
                    {WEEK_DAYS.map(day => (
                        <div key={day} className="text-center text-sm font-semibold text-gray-400 uppercase tracking-wider">{day}</div>
                    ))}
                </div>

                <div className="flex-1 grid grid-cols-7 grid-rows-6 gap-2 md:gap-4 min-h-[600px]">
                    {gridData.map((cell, index) => {
                        const isToday = isSameDay(cell.date, new Date());
                        const dayEvents = approvedEvents.filter(e => isEventActiveOnDate(cell.date, e))
                                                .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

                        return (
                            <div 
                                key={index} 
                                className={`
                                    relative bg-white rounded-2xl p-2 border border-gray-100 
                                    transition-all hover:shadow-md flex flex-col gap-1 overflow-hidden group
                                    ${!cell.isCurrentMonth ? 'bg-gray-50/50 text-gray-400' : 'text-gray-700'}
                                    ${isToday ? 'ring-2 ring-blue-500 ring-offset-2' : ''}
                                `}
                            >
                                <div className="flex justify-between items-start">
                                    <span className={`text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white' : ''}`}>
                                        {cell.date.getDate()}
                                    </span>
                                </div>

                                <div className="flex-1 flex flex-col gap-1 overflow-y-auto custom-scrollbar mt-1">
                                    {dayEvents.map(event => (
                                        <div 
                                            key={event.id}
                                            data-id={event.id}
                                            onClick={(e) => handleEventClick(e, event)}
                                            className={`
                                                text-xs px-2 py-1 rounded-md truncate font-medium border-l-2 transition-transform hover:scale-[1.02] cursor-pointer flex items-center gap-1
                                                ${getRegionClasses(event.region)}
                                            `}
                                            title={`${event.title} (${event.isAllDay ? 'All Day' : formatTime(event.start)})${event.recurrence !== 'none' ? ' - Repeats ' + event.recurrence : ''}`}
                                        >
                                            {event.isAllDay ? '' : <span className="opacity-75 text-[10px] shrink-0">{formatTime(event.start)}</span>}
                                            <span className="truncate">{event.title}</span>
                                            {event.recurrence && event.recurrence !== 'none' && (
                                                <Repeat size={10} className="shrink-0 opacity-60" />
                                            )}
                                        </div>
                                    ))}
                                </div>

                                <div className="absolute bottom-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity hidden md:block">
                                    <button onClick={(e) => { e.stopPropagation(); handleDateClick(cell.date); }} className="bg-gray-100 p-1 rounded-full text-gray-400 hover:text-blue-600 hover:bg-blue-50 cursor-pointer">
                                        <Plus size={14} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </>
        )}
      </main>

      <EventModal 
        isOpen={isEventModalOpen}
        onClose={() => setIsEventModalOpen(false)}
        onSave={handleSaveEvent}
        onDelete={handleDeleteEvent}
        initialDate={selectedDate}
        existingEvent={selectedEvent}
        isAdmin={isAdminSession}
      />

      <LoginModal 
        isOpen={isLoginModalOpen}
        onClose={() => setIsLoginModalOpen(false)}
        onLoginSuccess={handleLoginSuccess}
      />
    </div>
  );
};
